const LOCAL_STORAGE_KEY = 'thisai_crm_payments'
const getLocalStorageKey = () => getScopedStorageKey(LOCAL_STORAGE_KEY, 'company')
const getInvoicesStorageKey = () => getScopedStorageKey('thisai_crm_invoices', 'company')

// Duplicate-submit guard for slow UI/network conditions.
// Prevents double payment entries when users click "Record Payment" repeatedly.
const PAYMENT_CREATE_DEDUP_WINDOW_MS = 8000
const inFlightPaymentCreateKeys = new Set<string>()
const recentCreatedPayments = new Map<string, { payment: Payment; timestamp: number }>()
const PAYMENT_OVERPAYMENT_TOLERANCE = 0.01

const normalizePaymentDedupPart = (value: unknown): string =>
  String(value ?? '').trim().toLowerCase()

const normalizeMoneyForPaymentDedup = (value: unknown): string => {
  const n = Number(value)
  if (!Number.isFinite(n)) return '0.00'
  return (Math.round(n * 100) / 100).toFixed(2)
}

const paymentMillis = (value: unknown): number => {
  const ms = new Date(String(value ?? '')).getTime()
  return Number.isFinite(ms) ? ms : 0
}

const buildPaymentCreateDedupKey = (
  paymentData: Partial<PaymentInput>,
  companyId: string
): string => {
  return [
    companyId,
    normalizePaymentDedupPart(paymentData.invoiceId),
    normalizePaymentDedupPart(paymentData.invoiceNumber),
    normalizeMoneyForPaymentDedup(paymentData.amount),
    normalizePaymentDedupPart(paymentData.paymentMode),
    normalizePaymentDedupPart(paymentData.paymentDate),
    normalizePaymentDedupPart(paymentData.reference),
    normalizePaymentDedupPart(paymentData.partyId)
  ].join('|')
}

const purgeRecentCreatedPaymentCache = () => {
  const now = Date.now()
  for (const [key, entry] of recentCreatedPayments.entries()) {
    if (now - entry.timestamp > PAYMENT_CREATE_DEDUP_WINDOW_MS) {
      recentCreatedPayments.delete(key)
    }
  }
}

const findRecentExistingPaymentByDedupKey = (
  dedupKey: string,
  companyId: string
): Payment | null => {
  purgeRecentCreatedPaymentCache()
  const cached = recentCreatedPayments.get(dedupKey)
  if (cached) {
    return cached.payment
  }

  const now = Date.now()
  const payments = getPaymentsFromLocalStorage()
  const matched = payments.find(p => {
    const pKey = buildPaymentCreateDedupKey(p as Partial<PaymentInput>, companyId)
    if (pKey !== dedupKey) return false

    const createdMs = paymentMillis((p as any)?.createdAt || (p as any)?.paymentDate)
    return createdMs > 0 && (now - createdMs) <= PAYMENT_CREATE_DEDUP_WINDOW_MS
  })

  return matched || null
}

const waitForRecentPaymentByDedupKey = async (
  dedupKey: string,
  companyId: string,
  timeoutMs: number = 3000
): Promise<Payment | null> => {
  const started = Date.now()
  while (Date.now() - started < timeoutMs) {
    const found = findRecentExistingPaymentByDedupKey(dedupKey, companyId)
    if (found) return found
    await new Promise(resolve => setTimeout(resolve, 120))
  }
  return null
}

const invalidatePaymentRelatedCaches = () => {
  // Invoice lists and party outstanding cards are cache-backed.
  // Payment updates must clear both to reflect immediately in UI.
  invalidateCacheByPrefix('invoices_')
  invalidateCacheByPrefix('parties_outstanding_')

  // Notify mounted pages to refresh their local state.
  emitDataEvent(DATA_EVENTS.PAYMENTS_CHANGED, { reason: 'payment' })
  emitDataEvent(DATA_EVENTS.INVOICES_CHANGED, { reason: 'payment' })
  emitDataEvent(DATA_EVENTS.PARTIES_CHANGED, { reason: 'payment' })
}

// Helper to generate offline-safe ID
const generateOfflineId = () => `payment_${Date.now()}_${Math.random().toString(36).substr(2, 9)}`

// Check if ID is offline-generated
const isOfflineId = (id: string) => id.startsWith('payment_') || id.startsWith('payment-') || id.startsWith('offline_')

/**
 * Helper function to deeply remove undefined values from an object
 */
function removeUndefinedDeep(obj: any): any {
  if (obj === null || obj === undefined) {
    return obj
  }

  if (Array.isArray(obj)) {
    return obj.map(item => removeUndefinedDeep(item))
  }

  if (typeof obj === 'object') {
    const cleaned: any = {}
    for (const [key, value] of Object.entries(obj)) {
      if (value !== undefined) {
        cleaned[key] = removeUndefinedDeep(value)
      }
    }
    return cleaned
  }

  return obj
}

export interface Payment {
  id: string
  invoiceId: string
  invoiceNumber: string
  invoiceType?: 'sale' | 'purchase'  // Added for ledger tracking
  partyId: string
  partyName: string
  companyId?: string
  amount: number
  paymentMode: 'cash' | 'bank' | 'upi' | 'card' | 'cheque'
  paymentDate: string
  reference?: string
  notes?: string
  createdAt: string
  createdBy: string
  // Banking fields
  bankAccountId?: string  // For bank payments
  bankName?: string       // For bank payments
}

export interface PaymentInput {
  invoiceId: string
  invoiceNumber: string
  invoiceType?: 'sale' | 'purchase'  // Added for ledger tracking
  partyId: string
  partyName: string
  amount: number
  paymentMode: 'cash' | 'bank' | 'upi' | 'card' | 'cheque'
  paymentDate: string
  reference?: string
  notes?: string
  bankAccountId?: string  // For bank payments
  bankName?: string       // For bank payments
}

/**
 * Record a payment against an invoice - OFFLINE FIRST
 * Also creates ledger entry for the party
 */
export async function recordPayment(paymentData: PaymentInput): Promise<Payment | null> {
  debugLog('[recordPayment] Starting offline-first creation...')
  debugLog('[recordPayment] Firebase ready:', isFirebaseReady())
  debugLog('[recordPayment] Device online:', isDeviceOnline())

  const now = new Date().toISOString()
  const id = generateOfflineId()
  const companyId = getCurrentCompanyId()

  if (!companyId) {
    console.warn('[recordPayment] Missing companyId - cannot record payment')
    return null
  }

  const dedupKey = buildPaymentCreateDedupKey(paymentData, companyId)
  const existingRecentPayment = findRecentExistingPaymentByDedupKey(dedupKey, companyId)
  if (existingRecentPayment) {
    console.warn('[recordPayment] Duplicate payment prevented (recent match):', paymentData.invoiceNumber)
    return existingRecentPayment
  }

  if (inFlightPaymentCreateKeys.has(dedupKey)) {
    const pendingPayment = await waitForRecentPaymentByDedupKey(dedupKey, companyId)
    if (pendingPayment) {
      console.warn('[recordPayment] Duplicate payment prevented (in-flight match):', paymentData.invoiceNumber)
      return pendingPayment
    }
    console.warn('[recordPayment] Duplicate payment prevented while previous request is still in progress')
    return null
  }

  inFlightPaymentCreateKeys.add(dedupKey)

  try {
    // Deep clean undefined values
    const cleanData = removeUndefinedDeep(paymentData)

    const newPayment: Payment = {
      ...cleanData,
      id,
      companyId,
      createdAt: now,
      createdBy: 'Current User',
      _pendingSync: !isDeviceOnline(),
      _savedAt: now,
      _syncedAt: null
    } as Payment

    // STEP 1: Always save locally first
    try {
      await saveToOffline(STORES.PAYMENTS, newPayment)
      // Also save to localStorage for backward compatibility
      const storageKey = getLocalStorageKey()
      const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
      if (Array.isArray(payments)) {
        payments.push(newPayment)
        markLocalJSONDirty(storageKey)
      }
      debugLog('[recordPayment] Payment saved locally:', id)
    } catch (error) {
      console.error('[recordPayment] Failed to save locally:', error)
      // Fallback to localStorage only
      const storageKey = getLocalStorageKey()
      const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
      if (Array.isArray(payments)) {
        payments.push(newPayment)
        markLocalJSONDirty(storageKey)
      }
    }

    // Update invoice payment status locally (including payment mode)
    debugLog('[recordPayment] Updating invoice payment status locally...')
    await updateInvoicePaymentInLocalStorage(paymentData.invoiceId, paymentData.amount, paymentData.paymentMode)
    invalidatePaymentRelatedCaches()

    // Create ledger entry for payment (works offline)
    if (paymentData.invoiceType && paymentData.partyId && paymentData.partyName) {
      debugLog('[recordPayment] Creating ledger entry...')
      await createPaymentLedgerEntry(
        paymentData.partyId,
        paymentData.partyName,
        paymentData.paymentDate,
        paymentData.amount,
        paymentData.reference || paymentData.invoiceNumber,
        paymentData.invoiceType
      )
      debugLog(`[recordPayment] Ledger entry created for payment to ${paymentData.partyName}`)
    }

    // STEP 2: If online, sync to Firebase silently
    if (isDeviceOnline() && isFirebaseReady()) {
      try {
        const serverData = removeUndefinedDeep({
          ...paymentData,
          companyId,
          createdAt: now,
          createdBy: 'Current User'
        })

        const docRef = await addDoc(collection(db!, COLLECTIONS.INVOICES + '_payments'), serverData)

        // Update local payment with Firebase ID
        const syncedPayment: Payment = {
          ...newPayment,
          id: docRef.id,
          _pendingSync: false,
          _syncedAt: now
        } as Payment

        // Remove old offline ID record and save with new Firebase ID
        await deleteFromOffline(STORES.PAYMENTS, id)
        await saveToOffline(STORES.PAYMENTS, syncedPayment)

        // Update localStorage too
        const storageKey = getLocalStorageKey()
        const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
        if (Array.isArray(payments)) {
          const idx = payments.findIndex(p => p.id === id)
          if (idx !== -1) payments.splice(idx, 1)
          payments.push(syncedPayment)
          markLocalJSONDirty(storageKey)
        }

        // Update Firebase invoice status
        await updateInvoicePaymentStatus(paymentData.invoiceId, paymentData.amount, paymentData.paymentMode)

        debugLog('[recordPayment] Synced to Firebase:', docRef.id)
        recentCreatedPayments.set(dedupKey, {
          payment: syncedPayment,
          timestamp: Date.now()
        })
        return syncedPayment
      } catch (error) {
        console.warn('[recordPayment] Firebase sync failed, queuing for later:', error)
        await addToSyncQueue('create', STORES.PAYMENTS, newPayment)
      }
    } else {
      debugLog('[recordPayment] Offline mode - queuing for sync')
      await addToSyncQueue('create', STORES.PAYMENTS, newPayment)
    }

    recentCreatedPayments.set(dedupKey, {
      payment: newPayment,
      timestamp: Date.now()
    })
    return newPayment
  } finally {
    inFlightPaymentCreateKeys.delete(dedupKey)
  }
}

/**
 * Get all payments for an invoice - OFFLINE FIRST
 */
export async function getInvoicePayments(invoiceId: string): Promise<Payment[]> {
  debugLog('📥 getInvoicePayments called for invoice:', invoiceId)
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    console.warn('[getInvoicePayments] Missing companyId - returning empty list')
    return []
  }

  // STEP 1: Always try IndexedDB first
  let localPayments: Payment[] = []
  try {
    const allPayments = await getAllFromOffline<Payment>(STORES.PAYMENTS)
    localPayments = allPayments.filter(p => p.invoiceId === invoiceId && p.companyId === companyId)
    // Sort by paymentDate descending
    localPayments.sort((a, b) => new Date(b.paymentDate).getTime() - new Date(a.paymentDate).getTime())
  } catch (error) {
    console.warn('IndexedDB read failed, trying localStorage:', error)
    localPayments = getInvoicePaymentsFromLocalStorage(invoiceId)
  }

  // STEP 2: If offline or Firebase not ready, return local data immediately
  if (!isDeviceOnline() || !isFirebaseReady()) {
    debugLog('📱 Offline mode: Returning', localPayments.length, 'payments from local storage')
    return localPayments
  }

  // STEP 3: If online, try to fetch from Firebase and merge
  try {
    const q = query(
      collection(db!, COLLECTIONS.INVOICES + '_payments'),
      where('companyId', '==', companyId),
      where('invoiceId', '==', invoiceId),
      orderBy('paymentDate', 'desc')
    )

    const snapshot = await getDocs(q)
    const serverPayments = snapshot.docs.map(doc => ({
      id: doc.id,
      ...doc.data()
    } as Payment))

    // Merge: Keep local-only items (offline created, not yet synced)
    const localOnlyPayments = localPayments.filter(p => isOfflineId(p.id))
    const mergedPayments = [...serverPayments, ...localOnlyPayments]

    // Update local cache with server data (in background)
    for (const payment of serverPayments) {
      saveToOffline(STORES.PAYMENTS, payment).catch(() => {})
    }

    debugLog('☁️ Retrieved from Firebase:', serverPayments.length, 'payments, merged with', localOnlyPayments.length, 'local')
    return mergedPayments.sort((a, b) => new Date(b.paymentDate).getTime() - new Date(a.paymentDate).getTime())
  } catch (error) {
    console.warn('Firebase fetch failed, returning local data:', error)
    return localPayments
  }
}

/**
 * Update invoice payment status after payment
 * Includes overpayment protection
 */
async function updateInvoicePaymentStatus(invoiceId: string, paidAmount: number, paymentMode?: string) {
  try {
    const invoiceRef = doc(db!, COLLECTIONS.INVOICES, invoiceId)
    const invoiceSnap = await getDoc(invoiceRef)

    if (invoiceSnap.exists()) {
      const invoice = invoiceSnap.data()
      // Check both nested payment.paidAmount and top-level paidAmount
      // Round to 2 decimal places to avoid floating-point precision issues
      const currentPaid = Math.round((invoice.payment?.paidAmount || invoice.paidAmount || 0) * 100) / 100
      const grandTotal = Math.round((invoice.grandTotal || invoice.total || 0) * 100) / 100
      const roundedPaidAmount = Math.round(paidAmount * 100) / 100
      const totalPaid = Math.round((currentPaid + roundedPaidAmount) * 100) / 100

      // Double-check: prevent overpayment (safety net)
      // Keep tolerance at paise level to avoid accidental over-collection.
      if (totalPaid > grandTotal + PAYMENT_OVERPAYMENT_TOLERANCE) {
        throw new Error(`Overpayment detected! Current: ₹${currentPaid.toFixed(2)}, Adding: ₹${roundedPaidAmount.toFixed(2)}, Total would be: ₹${totalPaid.toFixed(2)}, but invoice is only ₹${grandTotal.toFixed(2)}`)
      }

      const status = derivePaymentInfoStatusFromAmounts(totalPaid, grandTotal, PAYMENT_OVERPAYMENT_TOLERANCE)

      const updateData: any = {
        // Update nested payment object
        'payment.paidAmount': totalPaid,
        'payment.status': status,
        'payment.lastPaymentDate': new Date().toISOString(),
        // Also update top-level fields for consistency
        'paidAmount': totalPaid,
        'paymentStatus': toInvoicePaymentStatus(status)
      }

      // Also update the payment mode if provided
      if (paymentMode) {
        updateData['payment.mode'] = paymentMode
        updateData['paymentMode'] = paymentMode
      }

      await updateDoc(invoiceRef, updateData)
    }
  } catch (error) {
    console.error('Error updating invoice payment status:', error)
    throw error // Re-throw to prevent payment record creation
  }
}

/**
 * LOCAL STORAGE IMPLEMENTATIONS
 */

async function recordPaymentToLocalStorage(paymentData: PaymentInput): Promise<Payment> {
  debugLog('💾 Recording payment to localStorage...')

  const storageKey = getLocalStorageKey()
  const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
  const companyId = getCurrentCompanyId()

  const payment: Payment = {
    id: `payment-${Date.now()}`,
    ...paymentData,
    companyId: companyId || undefined,
    createdAt: new Date().toISOString(),
    createdBy: 'Current User'
  }

  if (Array.isArray(payments)) {
    payments.push(payment)
    markLocalJSONDirty(storageKey)
  }
  debugLog('✅ Payment saved to localStorage')

  // Update invoice in local storage (including payment mode)
  debugLog('🔄 Updating invoice in localStorage...')
  await updateInvoicePaymentInLocalStorage(paymentData.invoiceId, paymentData.amount, paymentData.paymentMode)
  debugLog('✅ Invoice updated in localStorage')

  // Create ledger entry for payment
  if (paymentData.invoiceType && paymentData.partyId && paymentData.partyName) {
    debugLog('📝 Creating ledger entry...')
    await createPaymentLedgerEntry(
      paymentData.partyId,
      paymentData.partyName,
      paymentData.paymentDate,
      paymentData.amount,
      paymentData.reference || paymentData.invoiceNumber,
      paymentData.invoiceType
    )
    debugLog('✅ Ledger entry created')
  }

  return payment
}

function getPaymentsFromLocalStorage(): Payment[] {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) return []

    const stored = getLocalJSON<Payment[]>(getLocalStorageKey(), [])
    const payments: Payment[] = Array.isArray(stored) ? stored.slice() : []
    return payments.filter(p => p.companyId === companyId)
  } catch (error) {
    console.error('Error reading payments from local storage:', error)
    return []
  }
}

function getInvoicePaymentsFromLocalStorage(invoiceId: string): Payment[] {
  const companyId = getCurrentCompanyId()
  if (!companyId) return []

  const allPayments = getPaymentsFromLocalStorage()
  return allPayments
    .filter(p => p.invoiceId === invoiceId && p.companyId === companyId)
    .sort((a, b) => new Date(b.paymentDate).getTime() - new Date(a.paymentDate).getTime())
}

async function updateInvoicePaymentInLocalStorage(invoiceId: string, paidAmount: number, paymentMode?: string) {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) {
      console.warn('[updateInvoicePaymentInLocalStorage] Missing companyId')
      return
    }
    // STEP 1: Try to get fresh invoice data from IndexedDB first (most up-to-date)
    let invoice: any = null
    try {
      invoice = await getFromOffline(STORES.INVOICES, invoiceId)
      debugLog('[updateInvoicePaymentInLocalStorage] Got invoice from IndexedDB:', invoiceId)
    } catch (e) {
      debugLog('[updateInvoicePaymentInLocalStorage] IndexedDB fetch failed, trying localStorage')
    }

    // STEP 2: Fall back to local cache (localStorage-backed) if IndexedDB doesn't have it
    const invoicesKey = getInvoicesStorageKey()
    const invoices = getMutableLocalJSON<any[]>(invoicesKey, [])
    const invoiceIndex = Array.isArray(invoices)
      ? invoices.findIndex((inv: any) => inv.id === invoiceId)
      : -1

    // If we got fresh data from IndexedDB, use its grandTotal for validation
    // Otherwise fall back to localStorage data
    if (!invoice && invoiceIndex !== -1) {
      invoice = invoices[invoiceIndex]
    }

    if (!invoice) {
      console.warn('[updateInvoicePaymentInLocalStorage] Invoice not found:', invoiceId)
      return
    }

    // Check both nested payment.paidAmount and top-level paidAmount
    // Round to 2 decimal places to avoid floating-point precision issues
    const currentPaid = Math.round((invoice.payment?.paidAmount || invoice.paidAmount || 0) * 100) / 100
    const grandTotal = Math.round((invoice.grandTotal || invoice.total || 0) * 100) / 100
    const roundedPaidAmount = Math.round(paidAmount * 100) / 100
    const totalPaid = Math.round((currentPaid + roundedPaidAmount) * 100) / 100

    debugLog('[updateInvoicePaymentInLocalStorage] Payment validation:', {
      invoiceId,
      currentPaid,
      adding: roundedPaidAmount,
      totalPaid,
      grandTotal
    })

    // Double-check: prevent overpayment (safety net)
    // Keep tolerance at paise level to avoid accidental over-collection.
    // This allows for minor floating-point discrepancies while still preventing actual overpayments
    if (totalPaid > grandTotal + PAYMENT_OVERPAYMENT_TOLERANCE) {
      throw new Error(`Overpayment detected! Current: ₹${currentPaid.toFixed(2)}, Adding: ₹${roundedPaidAmount.toFixed(2)}, Total would be: ₹${totalPaid.toFixed(2)}, but invoice is only ₹${grandTotal.toFixed(2)}`)
    }

    const status = derivePaymentInfoStatusFromAmounts(totalPaid, grandTotal, PAYMENT_OVERPAYMENT_TOLERANCE)

    // Update localStorage if the invoice exists there
    if (invoiceIndex !== -1) {
      // Update nested payment object
      invoices[invoiceIndex].payment = {
        ...invoices[invoiceIndex].payment,
        paidAmount: totalPaid,
        status: status,
        lastPaymentDate: new Date().toISOString(),
        // Update payment mode if provided
        ...(paymentMode && { mode: paymentMode })
      }

      // Also update top-level fields for consistency
      invoices[invoiceIndex].paidAmount = totalPaid
      invoices[invoiceIndex].paymentStatus = toInvoicePaymentStatus(status)
      // Also sync the grandTotal from IndexedDB to localStorage
      if (invoice.grandTotal) {
        invoices[invoiceIndex].grandTotal = invoice.grandTotal
        invoices[invoiceIndex].total = invoice.grandTotal
      }
      if (paymentMode) {
        invoices[invoiceIndex].paymentMode = paymentMode
      }

      markLocalJSONDirty(invoicesKey)
    }

    // Also update IndexedDB with the new payment status
    try {
      const updatedInvoice = {
        ...invoice,
        paidAmount: totalPaid,
        paymentStatus: toInvoicePaymentStatus(status),
        payment: {
          ...invoice.payment,
          paidAmount: totalPaid,
          status: status,
          lastPaymentDate: new Date().toISOString(),
          ...(paymentMode && { mode: paymentMode })
        }
      }
      await saveToOffline(STORES.INVOICES, updatedInvoice)
    } catch (e) {
      console.warn('[updateInvoicePaymentInLocalStorage] Failed to update IndexedDB:', e)
    }
  } catch (error) {
    console.error('Error updating invoice payment in local storage:', error)
    throw error // Re-throw to prevent payment record creation
  }
}

/**
 * Delete/reverse a payment - OFFLINE FIRST with FULL REVERSAL
 * Also updates invoice payment status and reverses banking effects
 */
export async function deletePayment(paymentId: string, invoiceId: string): Promise<boolean> {
  debugLog('[deletePayment] Starting offline-first deletion with full reversal for:', paymentId)

  // STEP 1: Get payment details first (for amount to reverse and other metadata)
  let paymentToDelete: Payment | null = null
  try {
    paymentToDelete = await getFromOffline<Payment>(STORES.PAYMENTS, paymentId)
  } catch (error) {
    const allPayments = getPaymentsFromLocalStorage()
    paymentToDelete = allPayments.find(p => p.id === paymentId) || null
  }

  if (!paymentToDelete) {
    console.warn('[deletePayment] Payment not found:', paymentId)
    return false
  }

  debugLog('[deletePayment] Payment to delete:', {
    id: paymentToDelete.id,
    amount: paymentToDelete.amount,
    mode: paymentToDelete.paymentMode,
    invoiceId: paymentToDelete.invoiceId,
    partyId: paymentToDelete.partyId
  })

  // STEP 2: REVERSE LEDGER ENTRIES for this payment
  if (paymentToDelete.partyId && paymentToDelete.paymentMode) {
    try {
      debugLog('[deletePayment] Reversing ledger entry for payment:', paymentToDelete.reference || paymentToDelete.id)
      
      // Create a reversal ledger entry for the payment
      await reverseLedgerEntry(
        paymentToDelete.partyId,
        paymentToDelete.reference || paymentToDelete.invoiceNumber,
        `Payment ${paymentToDelete.paymentMode} Reversed`
      )
      
      debugLog('[deletePayment] Ledger entry reversed successfully')
    } catch (ledgerError) {
      console.error('[deletePayment] Failed to reverse ledger entry:', ledgerError)
      // Continue with deletion even if ledger reversal fails
    }
  }

  // STEP 3: REVERSE BANKING/CASH EFFECTS
  try {
    if (paymentToDelete.paymentMode === 'cash') {
      // Reverse cash in hand (subtract what was added)
      const { updateCashInHand, saveBankingPageTransactions, getBankingPageTransactions } = await import('./bankingService')
      
      // Negative amount to reverse the cash addition
      await updateCashInHand(
        -paymentToDelete.amount, 
        `Payment Reversed - ${paymentToDelete.reference || paymentToDelete.invoiceNumber} (${paymentToDelete.partyName})`
      )

      // Add reversal transaction to banking history
      const transactions = await getBankingPageTransactions()
      const newTransaction = {
        id: Date.now() + Math.random(),
        type: 'debit' as const,
        description: `Payment Reversal - ${paymentToDelete.reference || paymentToDelete.invoiceNumber} (${paymentToDelete.partyName})`,
        amount: paymentToDelete.amount,
        date: new Date().toISOString().split('T')[0],
        account: 'Cash in Hand'
      }
      transactions.unshift(newTransaction)
      await saveBankingPageTransactions(transactions)

      debugLog('[deletePayment] 💰 Cash in Hand reversed: -₹', paymentToDelete.amount)
    } 
    else if (paymentToDelete.paymentMode === 'bank' && paymentToDelete.bankAccountId) {
      // Reverse bank account balance
      const { updateBankAccountBalance, getBankingPageData, saveBankingPageTransactions, getBankingPageTransactions } = await import('./bankingService')
      
      // Negative amount to reverse the bank addition
      await updateBankAccountBalance(parseInt(paymentToDelete.bankAccountId), -paymentToDelete.amount)

      // Get bank account name for transaction description
      const bankingData = await getBankingPageData()
      const bankAccount = bankingData?.bankAccounts?.find(
        (acc: any) => acc.id.toString() === paymentToDelete.bankAccountId
      )

      // Add reversal transaction to banking history
      const transactions = await getBankingPageTransactions()
      const newTransaction = {
        id: Date.now() + Math.random(),
        type: 'debit' as const,
        description: `Bank Payment Reversal - ${paymentToDelete.reference || paymentToDelete.invoiceNumber} (${paymentToDelete.partyName})`,
        amount: paymentToDelete.amount,
        date: new Date().toISOString().split('T')[0],
        account: bankAccount?.name || 'Bank Account'
      }
      transactions.unshift(newTransaction)
      await saveBankingPageTransactions(transactions)

      debugLog('[deletePayment] 🏦 Bank account reversed: -₹', paymentToDelete.amount)
    }
  } catch (bankingError) {
    console.error('[deletePayment] Failed to reverse banking effects:', bankingError)
    // Continue with deletion even if banking reversal fails
  }

  // STEP 4: Delete from local storage first
  try {
    await deleteFromOffline(STORES.PAYMENTS, paymentId)
    // Also delete from localStorage
    const storageKey = getLocalStorageKey()
    const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
    if (Array.isArray(payments)) {
      const idx = payments.findIndex(p => p.id === paymentId)
      if (idx !== -1) payments.splice(idx, 1)
      markLocalJSONDirty(storageKey)
    }
    debugLog('[deletePayment] ✅ Deleted locally:', paymentId)
  } catch (error) {
    console.error('[deletePayment] Local delete failed:', error)
    // Try localStorage only
    const storageKey = getLocalStorageKey()
    const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
    if (Array.isArray(payments)) {
      const idx = payments.findIndex(p => p.id === paymentId)
      if (idx !== -1) payments.splice(idx, 1)
      markLocalJSONDirty(storageKey)
    }
  }

  // STEP 5: Recalculate invoice payment status locally (after payment removal)
  await recalculateInvoicePaymentInLocalStorage(invoiceId)
  debugLog('[deletePayment] ✅ Invoice status recalculated locally')
  
  // Invalidate caches
  invalidatePaymentRelatedCaches()

  // STEP 6: If online and has Firebase ID, sync deletion
  if (isDeviceOnline() && isFirebaseReady() && !isOfflineId(paymentId)) {
    try {
      const paymentRef = doc(db!, COLLECTIONS.INVOICES + '_payments', paymentId)
      await deleteDoc(paymentRef)
      debugLog('[deletePayment] ✅ Deleted from Firebase:', paymentId)

      // Recalculate Firebase invoice status
      await recalculateInvoicePaymentStatus(invoiceId)
      debugLog('[deletePayment] ✅ Firebase invoice status recalculated')
    } catch (error) {
      console.warn('[deletePayment] Firebase delete failed, queuing:', error)
      await addToSyncQueue('delete', STORES.PAYMENTS, { id: paymentId, invoiceId })
    }
  } else if (!isOfflineId(paymentId)) {
    // Queue for sync if has Firebase ID but currently offline
    await addToSyncQueue('delete', STORES.PAYMENTS, { id: paymentId, invoiceId })
  }

  return true
}

// Legacy function preserved for backward compatibility
async function deletePaymentLegacy(paymentId: string, invoiceId: string): Promise<boolean> {
  debugLog('🔍 deletePayment (legacy) called for:', paymentId)

  if (!isFirebaseReady()) {
    debugLog('📱 Using localStorage for payment deletion')
    return deletePaymentFromLocalStorage(paymentId, invoiceId)
  }

  try {
    // Get payment details first (for amount to reverse)
    const paymentRef = doc(db!, COLLECTIONS.INVOICES + '_payments', paymentId)
    const paymentSnap = await getDoc(paymentRef)

    if (!paymentSnap.exists()) {
      console.error('Payment not found in Firebase:', paymentId)
      return false
    }

    const paymentData = paymentSnap.data()
    const amountToReverse = paymentData.amount || 0
    const paymentMode = paymentData.paymentMode || 'cash'

    // Delete the payment document
    await deleteDoc(paymentRef)
    debugLog('✅ Payment deleted from Firebase')

    // Recalculate invoice payment status
    await recalculateInvoicePaymentStatus(invoiceId)
    debugLog('✅ Invoice status recalculated')

    // Reverse cash/bank effects if needed
    if (paymentMode === 'cash') {
      try {
        const { updateCashInHand } = await import('./bankingService')
        await updateCashInHand(-amountToReverse, `Payment Reversed - ${paymentId}`)
        debugLog('[deletePaymentLegacy] 💰 Cash in Hand reversed')
      } catch (e) {
        console.warn('[deletePaymentLegacy] Could not reverse cash:', e)
      }
    }

    return true
  } catch (error) {
    console.error('❌ Error deleting payment:', error)
    return false
  }
}

/**
 * Recalculate invoice payment status from Firebase payments
 */
async function recalculateInvoicePaymentStatus(invoiceId: string) {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) {
      console.warn('[recalculateInvoicePaymentStatus] Missing companyId - skipping')
      return
    }

    const invoiceRef = doc(db!, COLLECTIONS.INVOICES, invoiceId)
    const invoiceSnap = await getDoc(invoiceRef)

    if (!invoiceSnap.exists()) {
      console.error('Invoice not found:', invoiceId)
      return
    }

    const invoice = invoiceSnap.data()
    const grandTotal = invoice.grandTotal || invoice.total || 0

    // Get all remaining payments for this invoice
    const q = query(
      collection(db!, COLLECTIONS.INVOICES + '_payments'),
      where('companyId', '==', companyId),
      where('invoiceId', '==', invoiceId)
    )
    const paymentsSnap = await getDocs(q)
    const totalPaid = paymentsSnap.docs.reduce((sum, doc) => sum + (doc.data().amount || 0), 0)

    const status = derivePaymentInfoStatusFromAmounts(totalPaid, grandTotal, PAYMENT_OVERPAYMENT_TOLERANCE)

    await updateDoc(invoiceRef, {
      'payment.paidAmount': totalPaid,
      'payment.status': status,
      'payment.lastPaymentDate': paymentsSnap.docs.length > 0
        ? paymentsSnap.docs[0].data().paymentDate
        : null,
      // Also update top-level fields for compatibility
      paidAmount: totalPaid,
      paymentStatus: toInvoicePaymentStatus(status),
      dueAmount: grandTotal - totalPaid
    })

    debugLog(`✅ Invoice ${invoiceId} status updated: ${status}, paid: ₹${totalPaid}`)
  } catch (error) {
    console.error('Error recalculating invoice payment status:', error)
    throw error
  }
}

/**
 * Delete payment from localStorage and recalculate invoice status
 */
function deletePaymentFromLocalStorage(paymentId: string, invoiceId: string): boolean {
  try {
    debugLog('💾 Deleting payment from localStorage...')

    const storageKey = getLocalStorageKey()
    const payments = getMutableLocalJSON<Payment[]>(storageKey, [])
    if (!Array.isArray(payments)) return false

    // Get the payment to know the amount being reversed
    const paymentIndex = payments.findIndex(p => p.id === paymentId)
    const paymentToDelete = paymentIndex >= 0 ? payments[paymentIndex] : null

    if (!paymentToDelete) {
      console.error('Payment not found:', paymentId)
      return false
    }

    const amountToReverse = paymentToDelete.amount
    const paymentMode = paymentToDelete.paymentMode

    // Remove payment from payments list
    payments.splice(paymentIndex, 1)
    markLocalJSONDirty(storageKey)
    debugLog('✅ Payment removed from localStorage')

    // Recalculate invoice payment status
    recalculateInvoicePaymentInLocalStorage(invoiceId)
    debugLog('✅ Invoice status recalculated')

    // Reverse the cash/bank balance update
    try {
      const bankingData = localStorage.getItem('bankingAccounts')
      if (bankingData && paymentMode === 'cash') {
        const accounts = JSON.parse(bankingData)
        const newCashBalance = (accounts.cashInHand?.balance || 0) - amountToReverse
        accounts.cashInHand = { balance: Math.max(0, newCashBalance) }
        localStorage.setItem('bankingAccounts', JSON.stringify(accounts))
        debugLog('💰 Cash in Hand reversed: -₹', amountToReverse)
      }
    } catch (error) {
      console.error('Error reversing cash balance:', error)
    }

    return true
  } catch (error) {
    console.error('Error deleting payment from localStorage:', error)
    return false
  }
}

/**
 * Recalculate invoice payment status based on remaining payments
 */
async function recalculateInvoicePaymentInLocalStorage(invoiceId: string) {
  try {
    const companyId = getCurrentCompanyId()
    if (!companyId) return

    const invoicesKey = getInvoicesStorageKey()
    const invoices = getMutableLocalJSON<any[]>(invoicesKey, [])
    if (!Array.isArray(invoices)) return
    const invoiceIndex = invoices.findIndex((inv: any) => inv.id === invoiceId)

    if (invoiceIndex !== -1) {
      const invoice = invoices[invoiceIndex]
      const grandTotal = invoice.grandTotal || invoice.total || 0

      // Get all remaining payments for this invoice
      const remainingPayments = getInvoicePaymentsFromLocalStorage(invoiceId)
      const totalPaid = remainingPayments.reduce((sum, p) => sum + p.amount, 0)

      const status = derivePaymentInfoStatusFromAmounts(totalPaid, grandTotal, PAYMENT_OVERPAYMENT_TOLERANCE)

      invoices[invoiceIndex].payment = {
        ...invoice.payment,
        paidAmount: totalPaid,
        status: status,
        lastPaymentDate: remainingPayments.length > 0
          ? remainingPayments[0].paymentDate
          : null
      }

      // Also update top-level fields for compatibility
      invoices[invoiceIndex].paidAmount = totalPaid
      invoices[invoiceIndex].paymentStatus = toInvoicePaymentStatus(status)
      invoices[invoiceIndex].dueAmount = grandTotal - totalPaid

      markLocalJSONDirty(invoicesKey)

      // Also update IndexedDB
      try {
        const updatedInvoice = {
          ...invoice,
          paidAmount: totalPaid,
          paymentStatus: toInvoicePaymentStatus(status),
          payment: {
            ...invoice.payment,
            paidAmount: totalPaid,
            status: status
          },
          dueAmount: grandTotal - totalPaid
        }
        await saveToOffline(STORES.INVOICES, updatedInvoice)
      } catch (e) {
        console.warn('[recalculateInvoicePaymentInLocalStorage] Failed to update IndexedDB:', e)
      }
    }
  } catch (error) {
    console.error('Error recalculating invoice payment:', error)
  }
}

/**
 * Get payment summary for dashboard
 */
export function getPaymentSummary(payments: Payment[]) {
  const total = payments.reduce((sum, p) => sum + p.amount, 0)

  const byMode = payments.reduce((acc, p) => {
    acc[p.paymentMode] = (acc[p.paymentMode] || 0) + p.amount
    return acc
  }, {} as Record<string, number>)

  return {
    total,
    count: payments.length,
    byMode
  }
}

/**
 * Get a payment by ID (for reversal purposes)
 */
export async function getPaymentById(paymentId: string): Promise<Payment | null> {
  debugLog('[getPaymentById] Looking for payment:', paymentId)
  
  const companyId = getCurrentCompanyId()
  if (!companyId) {
    console.warn('[getPaymentById] Missing companyId')
    return null
  }

  // Try IndexedDB first
  try {
    const payment = await getFromOffline<Payment>(STORES.PAYMENTS, paymentId)
    if (payment && payment.companyId === companyId) {
      debugLog('[getPaymentById] Found in IndexedDB')
      return payment
    }
  } catch (error) {
    // Not found in IndexedDB, try localStorage
  }

  // Try localStorage
  const allPayments = getPaymentsFromLocalStorage()
  const payment = allPayments.find(p => p.id === paymentId && p.companyId === companyId)
  if (payment) {
    debugLog('[getPaymentById] Found in localStorage')
    return payment
  }

  // If online and not found locally, try Firebase
  if (isDeviceOnline() && isFirebaseReady() && !isOfflineId(paymentId)) {
    try {
      const paymentRef = doc(db!, COLLECTIONS.INVOICES + '_payments', paymentId)
      const paymentSnap = await getDoc(paymentRef)
      
      if (paymentSnap.exists()) {
        const payment = { id: paymentSnap.id, ...paymentSnap.data() } as Payment
        debugLog('[getPaymentById] Found in Firebase')
        return payment
      }
    } catch (error) {
      console.warn('[getPaymentById] Firebase fetch failed:', error)
    }
  }

  debugLog('[getPaymentById] Payment not found')
  return null
}